label("C",10dir(0),E);
label("D",10dir(300)+(0,-10),E);

draw(10dir(300)+2dir(-135)--10dir(300)+dir(-135),linewidth(2));
[/asy]

ref_solution:
We might try sketching a diagram: [asy]
pair pA, pB, pC, pO, pD;
pA = (-5, 0);
pB = (0, 0);
pC = (0, 20);
pO = (0, 10);
pD = (-80/17, 20/17);
draw(pA--pB--pC--pA);
draw(pD--pB);
draw(circle(pO, 10));
label("$A$", pA, SW);
label("$B$", pB, S);
label("$C$", pC, N);
