label("$O$",O,SW);
label("$N$",N,S);
label("$Y$",Y,S);
label("$a$",(0,2.5),W);
label("$a$",(0,7.5),W);
label("$b$",(6,0),S);
label("$b$",(18,0),S);
label("13",(4,4),E);
label("26",(12,7),E);
draw(X--Y--O--cycle);
draw(M--N);
[/asy]

